scripts/migrate-cv-schema.ts.content:
#!/usr/bin/env tsx
/**
 * Migration script to transform existing CV and Cover Letter data
 * to match the official schema definitions
 * 
 * Run with: npx tsx scripts/migrate-cv-schema.ts
 */

import { db } from '../server/db';
import { drafts, finals } from '../shared/schema';
import { eq } from 'drizzle-orm';

interface OldCvFormat {
  contact?: {
    name: string;
    email: string;
    phone?: string;
    location?: string;
  };
  summary?: string;
  skills?: string[];
  experience?: Array<{
    company: string;
    role: string;
    years: string;
    highlights?: string[];
  }>;
  education?: Array<{
    institution: string;
    degree: string;
    years: string;
  }>;
  certifications?: string[];
}

interface OldCoverLetterFormat {
  greeting?: string;
  opening?: string;
  body?: string;
  closing?: string;
  signature?: string;
}

function transformCv(oldCv: OldCvFormat | any): any {
  // If it already has the new structure, return as-is
  if (oldCv.header && oldCv.profile_summary && oldCv.key_skills) {
    return oldCv;
  }

  // Transform old structure to new structure
  const nameParts = (oldCv.contact?.name || "Unknown").split(' ');
  const fullName = oldCv.contact?.name || "Unknown";

  return {
    header: {
      full_name: fullName,
      city_region: oldCv.contact?.location || undefined,
      phone: oldCv.contact?.phone || undefined,
      email: oldCv.contact?.email || "email@example.com",
      linkedin: undefined,
    },
    headline: "Professional",
    profile_summary: oldCv.summary || "Professional with diverse experience",
    key_skills: oldCv.skills?.slice(0, 12) || [],
    technical_skills: oldCv.skills?.join(', ') || "",
    experience: (oldCv.experience || []).map((exp: any) => {
      // Parse years like "2020-2023" into from_year and to_year
      const yearMatch = exp.years?.match(/(\d{4})-(\d{4}|Present)/);
      const fromYear = yearMatch ? parseInt(yearMatch[1]) : 2020;
      const toYear = yearMatch && yearMatch[2] !== 'Present' ? parseInt(yearMatch[2]) : null;

      return {
        employer: exp.company || "Company",
        location: undefined,
        title: exp.role || "Professional",
        dates: {
          from_year: fromYear,
          to_year: toYear,
        },
        overview: "Professional role",
        achievements: (exp.highlights || []).map((h: string) => ({
          bullet: h,
          situation: undefined,
          obstacle: undefined,
          action: undefined,
          result: undefined,
        })),
      };
    }),
    education: (oldCv.education || []).map((edu: any) => ({
      qualification: edu.degree || "Degree",
      institution: edu.institution || "University",
      city_country: undefined,
    })),
    certifications: oldCv.certifications || [],
    optional_sections: undefined,
  };
}

function transformCoverLetter(oldCl: OldCoverLetterFormat | any): any {
  // If it already has the new structure, return as-is
  if (oldCl.header && oldCl.meta && oldCl.paragraphs) {
    return oldCl;
  }

  // Transform old structure to new structure
  return {
    header: {
      full_name: "Candidate Name",
      contact_block: "Email | Phone | Location",
      city_region: undefined,
    },
    meta: {
      date_iso: new Date().toISOString().split('T')[0],
      recipient: {
        name: undefined,
        title: undefined,
        company: undefined,
        address: undefined,
      },
      subject: "Re: Application",
    },
    paragraphs: {
      opening: oldCl.opening || oldCl.greeting || "",
      alignment: oldCl.body || "",
      fit_evidence: "",
      closing: oldCl.closing || "",
    },
    sign_off: {
      closing: "Yours sincerely",
      name: oldCl.signature || "Candidate Name",
    },
  };
}

async function migrateData() {
  console.log("Starting CV schema migration...\n");

  // Get all drafts
  const allDrafts = await db.query.drafts.findMany();
  console.log(`Found ${allDrafts.length} draft records`);

  let draftsMigrated = 0;
  for (const draft of allDrafts) {
    try {
      const newCv = transformCv(draft.cvJsonb);
      const newCoverLetter = transformCoverLetter(draft.coverLetterJsonb);

      await db.update(drafts)
        .set({
          cvJsonb: newCv as any,
          coverLetterJsonb: newCoverLetter as any,
        })
        .where(eq(drafts.runId, draft.runId));

      draftsMigrated++;
      console.log(`✓ Migrated draft for run ${draft.runId}`);
    } catch (error) {
      console.error(`✗ Failed to migrate draft for run ${draft.runId}:`, error);
    }
  }

  // Get all finals
  const allFinals = await db.query.finals.findMany();
  console.log(`\nFound ${allFinals.length} final records`);

  let finalsMigrated = 0;
  for (const final of allFinals) {
    try {
      const newCv = transformCv(final.cvJsonb);
      const newCoverLetter = transformCoverLetter(final.coverLetterJsonb);

      await db.update(finals)
        .set({
          cvJsonb: newCv as any,
          coverLetterJsonb: newCoverLetter as any,
        })
        .where(eq(finals.runId, final.runId));

      finalsMigrated++;
      console.log(`✓ Migrated final for run ${final.runId}`);
    } catch (error) {
      console.error(`✗ Failed to migrate final for run ${final.runId}:`, error);
    }
  }

  console.log(`\n✅ Migration complete!`);
  console.log(`   Drafts migrated: ${draftsMigrated}/${allDrafts.length}`);
  console.log(`   Finals migrated: ${finalsMigrated}/${allFinals.length}`);

  process.exit(0);
}

migrateData().catch((error) => {
  console.error("Migration failed:", error);
  process.exit(1);
});

client/src/pages/ProcessingStatus.tsx.content:
import { useQuery } from "@tanstack/react-query";
import { useRoute } from "wouter";
import { CheckCircle2, Circle, Clock, AlertCircle, ArrowLeft } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Progress } from "@/components/ui/progress";
import type { Run } from "@shared/schema";
import { Link } from "wouter";

export default function ProcessingStatus() {
  const [, params] = useRoute("/status/:runId");
  const runId = params?.runId;

  const { data: run, isLoading } = useQuery<Run>({
    queryKey: ["/api/runs", runId],
    refetchInterval: (query) => {
      const run = query.state.data as Run | undefined;
      if (!run) return false;
      return ["COMPLETED", "FAILED"].includes(run.status) ? false : 2000;
    },
  });

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center space-y-4">
          <div className="animate-spin h-12 w-12 border-4 border-primary border-t-transparent rounded-full mx-auto"></div>
          <p className="text-muted-foreground">Loading status...</p>
        </div>
      </div>
    );
  }

  if (!run) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <Card className="p-8 text-center max-w-md">
          <AlertCircle className="h-12 w-12 text-destructive mx-auto mb-4" />
          <h2 className="text-xl font-semibold mb-2">Run Not Found</h2>
          <p className="text-muted-foreground mb-6">
            The processing run you're looking for doesn't exist.
          </p>
          <Link href="/">
            <Button data-testid="button-return-not-found">Return to Dashboard</Button>
          </Link>
        </Card>
      </div>
    );
  }

  const stages = [
    { id: "QUEUED", label: "Queued", description: "Application submitted and queued for processing" },
    { id: "SCRAPING", label: "Analyzing Job", description: "Extracting job requirements and company information" },
    { id: "DRAFT_PASS1", label: "Generating Draft", description: "Creating initial CV and cover letter with AI" },
    { id: "OPTIMIZING_PASS2", label: "Optimizing", description: "Applying recommendations and refining documents" },
    { id: "VALIDATED", label: "Validating", description: "Ensuring ATS compliance and formatting standards" },
    { id: "RENDERING", label: "Rendering", description: "Generating professional PDF documents" },
    { id: "COMPLETED", label: "Completed", description: "All documents ready for download" },
  ];

  const currentStageIndex = stages.findIndex(s => s.id === run.status);
  const progress = run.status === "FAILED" ? 0 : ((currentStageIndex + 1) / stages.length) * 100;

  const getStageIcon = (stageId: string) => {
    const stageIndex = stages.findIndex(s => s.id === stageId);

    if (run.status === "FAILED") {
      return <AlertCircle className="h-6 w-6 text-destructive" />;
    }

    if (stageIndex < currentStageIndex) {
      return <CheckCircle2 className="h-6 w-6 text-green-600" data-testid={`icon-completed-${stageId}`} />;
    } else if (stageIndex === currentStageIndex) {
      return <Clock className="h-6 w-6 text-primary animate-pulse" data-testid={`icon-current-${stageId}`} />;
    } else {
      return <Circle className="h-6 w-6 text-muted-foreground" data-testid={`icon-pending-${stageId}`} />;
    }
  };

  return (
    <div className="min-h-screen bg-background">
      <div className="max-w-4xl mx-auto px-6 py-12">
        <div className="mb-8">
          <Link href="/">
            <Button variant="ghost" size="sm" data-testid="button-back">
              <ArrowLeft className="h-4 w-4 mr-2" />
              Back to Dashboard
            </Button>
          </Link>
        </div>

        <Card className="p-8">
          <div className="mb-8">
            <h1 className="text-3xl font-semibold mb-2">Processing Status</h1>
            <p className="text-muted-foreground" data-testid="text-job-url">
              {run.jobPostUrl}
            </p>
          </div>

          {/* Progress Bar */}
          <div className="mb-12">
            <div className="flex items-center justify-between mb-2">
              <span className="text-sm font-medium" data-testid="text-current-status">
                {run.status === "FAILED" ? "Processing Failed" : stages[currentStageIndex]?.label || run.status}
              </span>
              <span className="text-sm text-muted-foreground" data-testid="text-progress">
                {Math.round(progress)}%
              </span>
            </div>
            <Progress value={progress} className="h-2" data-testid="progress-bar" />
          </div>

          {/* Error Message */}
          {run.status === "FAILED" && run.errorMessage && (
            <div className="mb-8 p-4 bg-destructive/10 border border-destructive/20 rounded-md">
              <div className="flex items-start space-x-3">
                <AlertCircle className="h-5 w-5 text-destructive flex-shrink-0 mt-0.5" />
                <div>
                  <h3 className="font-semibold text-destructive mb-1">Processing Failed</h3>
                  <p className="text-sm text-destructive/90" data-testid="text-error">
                    {run.errorMessage}
                  </p>
                </div>
              </div>
            </div>
          )}

          {/* Timeline */}
          <div className="space-y-6">
            <h2 className="text-lg font-semibold">Processing Pipeline</h2>

            <div className="space-y-4">
              {stages.map((stage, index) => (
                <div
                  key={stage.id}
                  className="flex items-start space-x-4"
                  data-testid={`stage-${stage.id}`}
                >
                  <div className="flex-shrink-0 mt-1">
                    {getStageIcon(stage.id)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center space-x-2">
                      <h3 className="font-semibold" data-testid={`text-stage-${stage.id}`}>
                        {stage.label}
                      </h3>
                      {index < currentStageIndex && (
                        <span className="text-xs text-green-600 font-medium">Done</span>
                      )}
                      {index === currentStageIndex && run.status !== "FAILED" && (
                        <span className="text-xs text-primary font-medium">In Progress</span>
                      )}
                    </div>
                    <p className="text-sm text-muted-foreground">
                      {stage.description}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Action Buttons */}
          <div className="flex items-center space-x-4 pt-8 border-t border-border mt-8">
            {run.status === "COMPLETED" && (
              <Link href={`/results/${run.id}`}>
                <Button data-testid="button-view-results">
                  View Results
                </Button>
              </Link>
            )}
            {run.status === "FAILED" && (
              <Link href="/submit">
                <Button data-testid="button-retry">
                  Submit New Application
                </Button>
              </Link>
            )}
            {!["COMPLETED", "FAILED"].includes(run.status) && (
              <div className="text-sm text-muted-foreground" data-testid="text-processing-info">
                Processing typically takes 2-4 minutes. This page will auto-refresh.
              </div>
            )}
          </div>
        </Card>
      </div>
    </div>
  );
}

